{
  "sentences": [
    {
      "text": "你必須準時到公司。",
      "pinyin": "Nǐ bìxū zhǔnshí dào gōngsī.",
      "pinyin_numeric": "ni3 bi4xu1 zhun3shi2 dao4 gong1si1",
      "translation_en": "You must arrive at the company on time.",
      "translation_ko": "당신은 정시에 회사에 도착해야 합니다."
    },
    {
      "text": "我們必須遵守規定。",
      "pinyin": "Wǒmen bìxū zūnshǒu guīdìng.",
      "pinyin_numeric": "wo3men bi4xu1 zun1shou3 gui1ding4",
      "translation_en": "We must follow the rules.",
      "translation_ko": "우리는 규정을 지켜야 합니다."
    },
    {
      "text": "你必須先吃早餐再出門。",
      "pinyin": "Nǐ bìxū xiān chī zǎocān zài chūmén.",
      "pinyin_numeric": "ni3 bi4xu1 xian1 chi1 zao3can1 zai4 chu1men2",
      "translation_en": "You must eat breakfast before going out.",
      "translation_ko": "당신은 먼저 아침을 먹고 나가야 합니다."
    },
    {
      "text": "他必須去醫院看醫生。",
      "pinyin": "Tā bìxū qù yīyuàn kàn yīshēng.",
      "pinyin_numeric": "ta1 bi4xu1 qu4 yi1yuan4 kan4 yi1sheng1",
      "translation_en": "He must go to the hospital to see a doctor.",
      "translation_ko": "그는 병원에 가서 의사를 만나야 합니다."
    },
    {
      "text": "你必須帶悠遊卡才能搭捷運。",
      "pinyin": "Nǐ bìxū dài yōuyóukǎ cáinéng dā jiéyùn.",
      "pinyin_numeric": "ni3 bi4xu1 dai4 you1you2ka3 cai2neng2 da1 jie2yun4",
      "translation_en": "You must bring an EasyCard to take the MRT.",
      "translation_ko": "당신은 유유카드를 가지고 있어야 지하철을 탈 수 있습니다."
    },
    {
      "text": "我們必須在晚上十點前回家。",
      "pinyin": "Wǒmen bìxū zài wǎnshàng shí diǎn qián huíjiā.",
      "pinyin_numeric": "wo3men bi4xu1 zai4 wan3shang4 shi2 dian3 qian2 hui2jia1",
      "translation_en": "We must go home before ten o'clock in the evening.",
      "translation_ko": "우리는 저녁 10시 전에 집에 돌아가야 합니다."
    },
    {
      "text": "你必須說中文才能進步。",
      "pinyin": "Nǐ bìxū shuō zhōngwén cáinéng jìnbù.",
      "pinyin_numeric": "ni3 bi4xu1 shuo1 zhong1wen2 cai2neng2 jin4bu4",
      "translation_en": "You must speak Chinese to make progress.",
      "translation_ko": "당신은 중국어를 말해야 발전할 수 있습니다."
    },
    {
      "text": "他必須做功課才能看電視。",
      "pinyin": "Tā bìxū zuò gōngkè cáinéng kàn diànshì.",
      "pinyin_numeric": "ta1 bi4xu1 zuo4 gong1ke4 cai2neng2 kan4 dian4shi4",
      "translation_en": "He must do his homework before watching TV.",
      "translation_ko": "그는 숙제를 해야 텔레비전을 볼 수 있습니다."
    },
    {
      "text": "你必須帶傘，因為今天會下雨。",
      "pinyin": "Nǐ bìxū dài sǎn, yīnwèi jīntiān huì xiàyǔ.",
      "pinyin_numeric": "ni3 bi4xu1 dai4 san3, yin1wei4 jin1tian1 hui4 xia4yu3",
      "translation_en": "You must bring an umbrella because it will rain today.",
      "translation_ko": "당신은 우산을 가져가야 합니다. 오늘 비가 올 것이기 때문입니다."
    },
    {
      "text": "我們必須在捷運站裡面等。",
      "pinyin": "Wǒmen bìxū zài jiéyùn zhàn lǐmiàn děng.",
      "pinyin_numeric": "wo3men bi4xu1 zai4 jie2yun4 zhan4 li3mian4 deng3",
      "translation_en": "We must wait inside the MRT station.",
      "translation_ko": "우리는 지하철역 안에서 기다려야 합니다."
    }
  ]
}
